29	async fn main() -> anyhow::Result<()> {
30	    // Initialise structured logging.
31	    tracing_subscriber::registry()
32	        .with(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
33	        .with(tracing_subscriber::fmt::layer())
