39	        port = cfg.omega_port,
40	        runtime_profile = %cfg.omega_runtime_profile,
41	        "omega-gateway starting"
42	    );
43	    omega_gateway::livekit::log_livekit_status(&cfg);
44	    if !cfg.omega_anthropic_api_key.is_empty() {
45	        tracing::info!(
46	            model = %cfg.omega_anthropic_model,
47	            base_url = %cfg.omega_anthropic_base_url,
48	            "Anthropic provider configured"
49	        );
50	    }
51	    tracing::info!(
52	        system_prompt_path = %cfg.omega_system_prompt_path,
53	        "Dynamic system prompt target configured"
54	    );
55	    tracing::info!(
56	        local_base_url = %cfg.omega_local_base_url,
57	        local_model = %cfg.omega_local_model,
58	        "Local Ollama provider configured"
59	    );
60	    let cli_home = cfg.effective_cli_home_dir();
61	    let codex_model = cfg.effective_codex_cli_model();
62	    let claude_model = cfg.effective_claude_cli_model();
63	    tracing::info!(
64	        cli_home = %cli_home,
